#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Solve AoC 2025 Day 9: Movie Theater

typedef long long ll;

static int cmp_int(const void *a, const void *b) {
    int x = *(int*)a, y = *(int*)b;
    return x < y ? -1 : x > y ? 1 : 0;
}

// Remove duplicates from sorted array, return new size
static int unique(int *arr, int n) {
    if (n == 0) return 0;
    int k = 0;
    for (int i = 0; i < n; i++) {
        if (i == 0 || arr[i] != arr[i-1]) arr[k++] = arr[i];
    }
    return k;
}

// Binary search: find index of val in sorted array
static int find_idx(int *arr, int n, int val) {
    int lo = 0, hi = n - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (arr[mid] == val) return mid;
        else if (arr[mid] < val) lo = mid + 1;
        else hi = mid - 1;
    }
    return -1; // not found
}

int main(int argc, char *argv[]) {
    int part = 0;
    if (argc > 1) part = atoi(argv[1]);

    FILE *f = fopen("input.txt", "r");
    if (!f) { perror("input.txt"); return 1; }

    int xs[2000], ys[2000];
    int n = 0;
    int x, y;
    while (fscanf(f, "%d,%d", &x, &y) == 2) {
        xs[n] = x; ys[n] = y; n++;
    }
    fclose(f);

    // ---- Part 1 ----
    // For each pair of red tiles, compute area of rectangle with them as opposite corners
    // Area = (|x2-x1|+1) * (|y2-y1|+1)
    ll best1 = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            ll dx = xs[j] - xs[i]; if (dx < 0) dx = -dx;
            ll dy = ys[j] - ys[i]; if (dy < 0) dy = -dy;
            ll area = (dx + 1) * (dy + 1);
            if (area > best1) best1 = area;
        }
    }

    if (part == 1) {
        printf("Part 1: %lld\n", best1);
        return 0;
    }

    // ---- Part 2 ----
    // The red tiles form a rectilinear polygon (edges are horizontal/vertical segments)
    // Green tiles = edges + interior
    // Rectangle must have red tiles at opposite corners and all tiles must be red or green

    // Step 1: Coordinate compression
    // Collect all x and y coords of red tiles
    // The polygon edges go between consecutive tiles (horizontally or vertically)
    // Between adjacent coordinates, the inside/outside status is uniform
    // So we need to compress at tile coordinates AND the gaps between them

    // For a rectilinear polygon, we compress by including each coordinate value
    // AND each coordinate value +1 (to represent "between" segments)
    // This ensures each compressed cell is uniformly inside or outside

    // Actually the standard approach: collect all distinct x values and y values,
    // then between xs[i] and xs[i+1] there might be a gap.
    // We can represent each gap as a separate "cell" in compressed space.
    // But for our purposes, we just need to know for each compressed cell whether
    // it's inside/on the polygon.

    // Simpler: since all edges are axis-aligned and connect consecutive red tiles,
    // let's use ray casting on the compressed grid.

    // Collect all unique x and y coordinates
    int cxs[4000], cys[4000];
    int ncx = 0, ncy = 0;

    // We need x and x+1, y and y+1 style for proper boundary handling
    // Actually let's just use the coordinates of the vertices
    // For interior detection, we'll use the scanline approach:
    // For each row y in the polygon, the interior is determined by
    // the edges crossing that row.

    // Let me use a different approach:
    // 1. Compress coordinates (just the actual coordinates, plus midpoints between adjacent ones)
    //    to handle proper inside/outside for cells between vertex rows/columns.
    // 2. For each compressed cell, check if it's inside the polygon using ray casting.

    // Collect unique x values
    for (int i = 0; i < n; i++) cxs[ncx++] = xs[i];
    qsort(cxs, ncx, sizeof(int), cmp_int);
    ncx = unique(cxs, ncx);

    // Also add midpoints (xs[i]+1 style) to represent "between" x values
    // We'll add "xs[i]+1" for each x (to represent the strip between xs[i] and next xs)
    // Actually for a proper compressed representation, we want to represent ALL regions.
    // Let me add all xi and xi+1 for each distinct x, similarly for y.

    // For this problem, the rectangle must align with RED tile coordinates.
    // Red tiles have specific x,y values. The rectangle corners are at these values.
    // We need to check if ALL tiles in the rectangle [x1..x2] x [y1..y2] are valid.

    // The polygon has axis-aligned edges. Between two consecutive x-coordinates (of vertices),
    // the inside/outside status in x-direction is the same for all x values in that range.
    // So we can use compressed x,y where we include xi and xi+1 for each vertex xi.

    // Let's build compressed arrays with xi and xi+1 for each vertex coordinate.
    ncx = 0; ncy = 0;
    for (int i = 0; i < n; i++) {
        cxs[ncx++] = xs[i];
        cxs[ncx++] = xs[i] + 1;
        cys[ncy++] = ys[i];
        cys[ncy++] = ys[i] + 1;
    }
    qsort(cxs, ncx, sizeof(int), cmp_int);
    ncx = unique(cxs, ncx);
    qsort(cys, ncy, sizeof(int), cmp_int);
    ncy = unique(cys, ncy);

    // For each compressed cell (ci, cj), it represents real tiles [cxs[ci], cxs[ci+1]-1] x [cys[cj], cys[cj+1]-1]
    // (Well, each cxs[ci] itself is a single column or the start of a range)
    // Actually in our representation: compressed index ci represents ALL real x values from cxs[ci] to cxs[ci+1]-1
    // (if ci < ncx-1), or just cxs[ci] if last.

    // For ray casting: a point is inside polygon if a ray in one direction crosses an odd number of edges.
    // For rectilinear polygon, cast a ray upward (decreasing y) from point (px, py):
    // count horizontal edges that cross the ray.

    // The polygon edges: consecutive pairs (i, i+1 mod n) are either horizontal or vertical.
    // For ray casting upward from (px, py), count horizontal edges (y_edge < py) 
    // where x_edge_min <= px <= x_edge_max.

    // For "on boundary": point is on an edge.

    // Let's collect all horizontal and vertical edges
    // Edge i: from (xs[i], ys[i]) to (xs[(i+1)%n], ys[(i+1)%n])

    // For compressed cell (ci, cj), use the representative point (cxs[ci], cys[cj]) for ray casting.

    // Build valid grid
    // valid[cj][ci] = 1 if cell is inside or on boundary

    // Allocate grid
    int *valid = (int*)calloc(ncx * ncy, sizeof(int));

    // For each compressed cell, determine if it's inside/on boundary
    for (int cj = 0; cj < ncy; cj++) {
        int py = cys[cj];
        for (int ci = 0; ci < ncx; ci++) {
            int px = cxs[ci];

            // Check if (px, py) is on any edge
            int on_boundary = 0;
            int crossings = 0;

            for (int i = 0; i < n; i++) {
                int x1 = xs[i], y1 = ys[i];
                int x2 = xs[(i+1)%n], y2 = ys[(i+1)%n];

                if (y1 == y2) {
                    // Horizontal edge
                    int xmin = x1 < x2 ? x1 : x2;
                    int xmax = x1 > x2 ? x1 : x2;
                    if (py == y1 && px >= xmin && px <= xmax) {
                        on_boundary = 1;
                        break;
                    }
                    // Ray casting: ray going upward (decreasing y) from (px, py)
                    // This horizontal edge is crossed if y1 < py and xmin <= px <= xmax
                    if (y1 < py && px >= xmin && px <= xmax) {
                        crossings++;
                    }
                } else {
                    // Vertical edge
                    int ymin = y1 < y2 ? y1 : y2;
                    int ymax = y1 > y2 ? y1 : y2;
                    if (px == x1 && py >= ymin && py <= ymax) {
                        on_boundary = 1;
                        break;
                    }
                }
            }

            if (on_boundary || (crossings % 2 == 1)) {
                valid[cj * ncx + ci] = 1;
            }
        }
    }

    // Now find compressed indices for red tiles
    // For each red tile (xs[i], ys[i]), find its compressed index
    // ci_red[i] = find_idx(cxs, ncx, xs[i])
    // cj_red[i] = find_idx(cys, ncy, ys[i])

    int *ci_red = (int*)malloc(n * sizeof(int));
    int *cj_red = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        ci_red[i] = find_idx(cxs, ncx, xs[i]);
        cj_red[i] = find_idx(cys, ncy, ys[i]);
    }

    // Build 2D prefix sum of (1 - valid) to count invalid cells
    // prefix[cj][ci] = number of invalid compressed cells in [0..ci-1] x [0..cj-1]
    // But we want to count invalid compressed cells weighted by their real size? 
    // No - we want to know if ANY compressed cell in range is invalid.
    // A compressed cell is invalid if valid[cj*ncx+ci] == 0.
    // If prefix sum of invalid count is 0 in range, then all cells are valid.

    // prefix[j][i] = sum of (1-valid) for cells [0..i-1] x [0..j-1]
    int *prefix = (int*)calloc((ncx + 1) * (ncy + 1), sizeof(int));

    for (int cj = 0; cj < ncy; cj++) {
        for (int ci = 0; ci < ncx; ci++) {
            int inv = 1 - valid[cj * ncx + ci];
            prefix[(cj+1)*(ncx+1) + (ci+1)] = inv
                + prefix[cj*(ncx+1) + (ci+1)]
                + prefix[(cj+1)*(ncx+1) + ci]
                - prefix[cj*(ncx+1) + ci];
        }
    }

    // Query: sum of invalid cells in compressed rectangle [ci1..ci2] x [cj1..cj2]
    // (inclusive)
    #define QUERY(ci1, ci2, cj1, cj2) \
        (prefix[(cj2+1)*(ncx+1) + (ci2+1)] \
        - prefix[cj1*(ncx+1) + (ci2+1)] \
        - prefix[(cj2+1)*(ncx+1) + ci1] \
        + prefix[cj1*(ncx+1) + ci1])

    // For each pair of red tiles, check if their rectangle is entirely valid
    // The real rectangle [x1..x2] x [y1..y2] corresponds to compressed cells
    // from ci1 to ci2 in x (where cxs[ci1]=x1, cxs[ci2]=x2) and similarly for y.
    // But we need to include ALL compressed cells between ci1 and ci2.
    // ci1 = find_idx(cxs, ncx, x1), ci2 = find_idx(cxs, ncx, x2)
    // Since we added both xi and xi+1, the real cells between x1 and x2 are covered
    // by compressed indices ci1..ci2.
    // Wait: we need to verify this. cxs[ci1]=x1, cxs[ci2]=x2.
    // Between x1 and x2, all real tiles are covered.
    // Compressed cells ci1..ci2-1 cover real x values cxs[ci]..cxs[ci+1]-1.
    // Compressed cell ci2 covers just cxs[ci2] = x2.
    // So compressed range ci1..ci2 covers real x values x1..x2. Good.

    ll best2 = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (xs[i] == xs[j] && ys[i] == ys[j]) continue;

            int ci1 = ci_red[i], ci2 = ci_red[j];
            if (ci1 > ci2) { int t = ci1; ci1 = ci2; ci2 = t; }
            int cj1 = cj_red[i], cj2 = cj_red[j];
            if (cj1 > cj2) { int t = cj1; cj1 = cj2; cj2 = t; }

            // Check if all compressed cells in [ci1..ci2] x [cj1..cj2] are valid
            int inv_count = QUERY(ci1, ci2, cj1, cj2);
            if (inv_count == 0) {
                // All valid! Compute real area
                ll dx = xs[j] - xs[i]; if (dx < 0) dx = -dx;
                ll dy = ys[j] - ys[i]; if (dy < 0) dy = -dy;
                ll area = (dx + 1) * (dy + 1);
                if (area > best2) best2 = area;
            }
        }
    }

    free(valid);
    free(prefix);
    free(ci_red);
    free(cj_red);

    if (part == 2) {
        printf("Part 2: %lld\n", best2);
        return 0;
    }

    printf("Part 1: %lld\n", best1);
    printf("Part 2: %lld\n", best2);

    return 0;
}

