    printf("..XXXXXXXXXX..\n");
    printf("..#XXXXXX#XX..\n");
    printf(".........XXX..\n");
    printf(".........#X#..\n");
    printf("..............\n");

    // Check rectangle (2,3)-(9,5): x=[2,9], y=[3,5]
    printf("\nChecking rectangle (2,3)-(9,5): x=[2,9], y=[3,5]\n");
    int all_valid = 1;
