    int n = 0;
    int x, y;
    while (fscanf(f, "%d,%d", &x, &y) == 2) {
        xs[n] = x; ys[n] = y; n++;
    }
    fclose(f);

    // ---- Part 1 ----
    // For each pair of red tiles, compute area of rectangle with them as opposite corners
    ll best1 = 0;
    for (int i = 0; i < n; i++) {
